  ('NanoSpot.ai', 'www.nanospot.ai', 'https://cdn.brandfetch.io/idYpxe0GgK/w/121/h/33/theme/dark/logo.png?c=1bxrd51ni3el59qszywja62qjrcpMf2aUcx')
)
UPDATE startup_profiles sp
SET
  logo_url = pl.logo_url,
  updated_at = NOW()
FROM precise_logos pl
WHERE sp.name = pl.name
  AND sp.website IS NOT DISTINCT FROM pl.website;
